import{_ as a,c as e,o,a2 as p}from"./chunks/framework.CriqKoQt.js";const m=JSON.parse('{"title":"PUBGM 赛事笔记","description":"","frontmatter":{},"headers":[],"relativePath":"docs/2026上/note-pubgm-match.md","filePath":"docs/2026上/note-pubgm-match.md","lastUpdated":1774915389000}'),c={name:"docs/2026上/note-pubgm-match.md"};function n(s,t,l,r,d,u){return o(),e("div",null,t[0]||(t[0]=[p('<div class="info custom-block"><p class="custom-block-title">作者</p><p>novlan1</p><p>2026.1.1</p></div><h1 id="pubgm-赛事笔记" tabindex="-1">PUBGM 赛事笔记 <a class="header-anchor" href="#pubgm-赛事笔记" aria-label="Permalink to &quot;PUBGM 赛事笔记&quot;">​</a></h1><h2 id="openclaw-爆火的底层原因" tabindex="-1">Openclaw 爆火的底层原因 <a class="header-anchor" href="#openclaw-爆火的底层原因" aria-label="Permalink to &quot;Openclaw 爆火的底层原因&quot;">​</a></h2><p><code>2026-03-13</code></p><p>Openclaw 爆火的底层原因</p><p>一、解放时间，随时随地指挥 AI 干活</p><p>时间是人最宝贵的资产。Openclaw 最核心的价值，在于打破了&quot;必须坐在电脑前、打开 IDE 或终端&quot;才能使用 AI 的限制。无论你在通勤路上、会议间隙还是睡前，都可以直接指挥 AI 完成工作。这不是效率的小幅提升，而是对人的时间结构的彻底重塑——把原本&quot;碎片化等待&quot;的时间，变成了真实的生产力。</p><p>二、降低门槛，真正解决工作效率问题</p><p>现有的 AI 产品（如豆包）虽然好用，但功能相对有限，更多停留在&quot;消费级&quot;场景。而普通人大部分的时间是在工作，真正能解决工作效率问题的工具，才是开天辟地的存在。Openclaw 让普通人无需技术背景，也能借助 AI 完成复杂的工作任务，极大降低了接触和使用 AI 的门槛，这是它真正意义上的普惠价值。</p><p>三、长期记忆，一劳永逸的个性化配置</p><p>Openclaw 能记住你的偏好、习惯和自定义配置，不随时间流逝而遗忘。你只需要&quot;教&quot;它一次，它便能持续以你熟悉的方式工作。这种长期记忆机制，消除了每次使用都要重新交代背景的摩擦感，真正做到&quot;越用越懂你&quot;，是一种一劳永逸的体验积累。</p><p>总结</p><p>Openclaw 的爆火，本质上是击中了三个核心需求：时间自由、工作提效、个性化沉淀。它不是一个工具的升级，而是人与 AI 协作方式的范式转变。</p><h2 id="test" tabindex="-1">test <a class="header-anchor" href="#test" aria-label="Permalink to &quot;test&quot;">​</a></h2><p><code>2026-03-10</code></p><p>test</p>',16)]))}const h=a(c,[["render",n]]);export{m as __pageData,h as default};
